-- ============================================================
-- BANCO DE PREGUNTAS - OFICIALES SUBALTERNOS PNP 2026
-- AscensoCim Peru - Script de creacion de tablas + datos
-- ============================================================

create table if not exists materias (
  id serial primary key,
  nombre text not null unique
);

create table if not exists preguntas (
  id serial primary key,
  numero integer not null,
  materia_id integer references materias(id),
  pregunta text not null,
  opciones jsonb not null,
  respuesta_correcta text,
  indice_correcto integer,
  ubicacion text,
  codigo text unique,
  created_at timestamptz default now()
);

create index if not exists idx_preguntas_materia on preguntas(materia_id);
create index if not exists idx_preguntas_codigo on preguntas(codigo);

-- ============================================================
-- MATERIAS
-- ============================================================
on conflict (id) do nothing;
select setval('materias_id_seq', (select max(id) from materias));

